SELECT COUNT(DISTINCT card_id) AS unique_cards_count
FROM player_cards
WHERE player_id = 1;

SELECT quantity
FROM player_cards
WHERE player_id = 1 AND card_id = 1;

SELECT player_id, COUNT(card_id) AS total_cards
FROM player_cards
GROUP BY player_id;

SELECT metric, value
FROM player_deck_performance
WHERE player_id = 1 AND deck_id = 1;

SELECT rarity_name
FROM rarities
WHERE rarity_name = 'N';
